import{_ as s,o as t,c as i,ak as e}from"./chunks/framework.DwHlt8HN.js";const b=JSON.parse('{"title":"数据库核心概念","description":"","frontmatter":{},"headers":[],"relativePath":"mysql/basic/db-concept.md","filePath":"mysql/basic/db-concept.md","lastUpdated":1774248380000}'),n={name:"mysql/basic/db-concept.md"};function l(d,a,r,h,p,o){return t(),i("div",null,[...a[0]||(a[0]=[e(`<h1 id="数据库核心概念" tabindex="-1">数据库核心概念 <a class="header-anchor" href="#数据库核心概念" aria-label="Permalink to “数据库核心概念”">​</a></h1><h2 id="为什么需要数据库" tabindex="-1">为什么需要数据库 <a class="header-anchor" href="#为什么需要数据库" aria-label="Permalink to “为什么需要数据库”">​</a></h2><p>你可能会想：我用 Excel 也能存数据，用 JSON 文件也能存数据，为什么非要搞一个数据库？</p><p>来看一个例子。</p><h3 id="没有数据库的世界" tabindex="-1">没有数据库的世界 <a class="header-anchor" href="#没有数据库的世界" aria-label="Permalink to “没有数据库的世界”">​</a></h3><p>假设你在做一个「学生成绩管理系统」：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># students.json</span></span>
<span class="line"><span>[</span></span>
<span class="line"><span>  {&quot;id&quot;: 1, &quot;name&quot;: &quot;张三&quot;, &quot;score&quot;: 92},</span></span>
<span class="line"><span>  {&quot;id&quot;: 2, &quot;name&quot;: &quot;李四&quot;, &quot;score&quot;: 88}</span></span>
<span class="line"><span>]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>文件存着，看起来没问题。但当数据量上来：</p><ul><li>查「数学成绩大于 90 分的学生」——你得用代码读整个文件、遍历、判断</li><li>100 个人同时查——文件被锁住，有人读不到</li><li>改了王五的成绩，保存的时候赵六刚好也在改——最后保存的人覆盖了另一个人的改动</li><li>要查「平均分」「不及格人数」「排名」——自己写代码算</li></ul><p>文件能存数据，但它不解决：<strong>查询、并发、安全、一致性</strong> 这些问题。</p><p>数据库，就是专门解决这些问题的系统。</p><h2 id="dbms-是什么" tabindex="-1">DBMS 是什么 <a class="header-anchor" href="#dbms-是什么" aria-label="Permalink to “DBMS 是什么”">​</a></h2><p><strong>DBMS（Database Management System）</strong> —— 数据库管理系统，是操作数据库的软件。</p><p>你不用直接读写磁盘文件，而是通过 DBMS 提供的接口（SQL）来操作数据。DBMS 帮你搞定：</p><ul><li>数据存在哪、怎么存</li><li>并发请求怎么处理</li><li>查询怎么快速返回</li><li>谁能访问什么数据</li></ul><p>MySQL、Oracle、PostgreSQL、SQL Server 都是 DBMS。</p><h2 id="常用-dbms-对比" tabindex="-1">常用 DBMS 对比 <a class="header-anchor" href="#常用-dbms-对比" aria-label="Permalink to “常用 DBMS 对比”">​</a></h2><table tabindex="0"><thead><tr><th>DBMS</th><th>类型</th><th>代表用户</th><th>特点</th></tr></thead><tbody><tr><td>MySQL</td><td>关系型</td><td>互联网公司</td><td>免费、轻量、社区活跃</td></tr><tr><td>PostgreSQL</td><td>关系型</td><td>互联网 + 传统企业</td><td>功能强大、扩展性好</td></tr><tr><td>Oracle</td><td>关系型</td><td>金融、大型企业</td><td>贵、稳定、功能最全</td></tr><tr><td>SQL Server</td><td>关系型</td><td>微软生态企业</td><td>Windows 集成度高</td></tr><tr><td>Redis</td><td>键值型</td><td>所有公司</td><td>内存数据库，高速缓存</td></tr><tr><td>MongoDB</td><td>文档型</td><td>互联网公司</td><td>无 schema，灵活性高</td></tr></tbody></table><p>对于大多数 Web 应用，MySQL 是最务实的选择——够用、免费、生态成熟。</p><h2 id="关系型数据库核心概念" tabindex="-1">关系型数据库核心概念 <a class="header-anchor" href="#关系型数据库核心概念" aria-label="Permalink to “关系型数据库核心概念”">​</a></h2><p><strong>RDBMS（Relational Database Management System）</strong> 是关系型数据库管理系统。它的核心思想是：<strong>用表（Table）来组织数据，表和表之间可以建立关系（Relation）</strong>。</p><h3 id="几个关键术语" tabindex="-1">几个关键术语 <a class="header-anchor" href="#几个关键术语" aria-label="Permalink to “几个关键术语”">​</a></h3><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 学生表</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TABLE</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> student</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    id      </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">INT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> PRIMARY KEY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 学号，主键，唯一标识</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    VARCHAR</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">50</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 姓名</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    age     </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">INT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,                 </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 年龄</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    class_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">INT</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                 -- 班级编号，外键</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><table tabindex="0"><thead><tr><th>术语</th><th>解释</th><th>例子</th></tr></thead><tbody><tr><td><strong>数据库（Database）</strong></td><td>存储数据的容器，一个 DBMS 可以管理多个数据库</td><td><code>school_db</code></td></tr><tr><td><strong>表（Table）</strong></td><td>数据的二维结构，行=记录，列=字段</td><td><code>student</code></td></tr><tr><td><strong>行（Row）</strong></td><td>一条记录，代表一个实体</td><td>张三的整行信息</td></tr><tr><td><strong>列（Column）</strong></td><td>一个字段，描述实体的某个属性</td><td><code>name</code>、<code>age</code></td></tr><tr><td><strong>主键（Primary Key）</strong></td><td>唯一标识每行，不能为空</td><td><code>id</code></td></tr><tr><td><strong>外键（Foreign Key）</strong></td><td>建立表与表之间的关联关系</td><td><code>class_id</code> 关联 <code>class</code> 表</td></tr></tbody></table><h3 id="举一个例子" tabindex="-1">举一个例子 <a class="header-anchor" href="#举一个例子" aria-label="Permalink to “举一个例子”">​</a></h3><p>一个学校管理系统，可能有以下几张表：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>student 表：学号、姓名、年龄、班级编号</span></span>
<span class="line"><span>class 表：班级编号、班级名称、班主任</span></span>
<span class="line"><span>course 表：课程编号、课程名称、学分</span></span>
<span class="line"><span>score 表：学号、课程编号、成绩</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>student 和 class 通过 <code>class_id</code> 关联，score 表把 student 和 course 关联起来——这就是<strong>关系型</strong>数据库的「关系」。</p><h2 id="sql-是什么" tabindex="-1">SQL 是什么 <a class="header-anchor" href="#sql-是什么" aria-label="Permalink to “SQL 是什么”">​</a></h2><p><strong>SQL（Structured Query Language）</strong> —— 结构化查询语言，是操作 RDBMS 的标准语言。</p><p>不管你用的是 MySQL、Oracle 还是 PostgreSQL，SQL 语法大体相通。学会一套，触类旁通。</p><p>SQL 的分类：</p><table tabindex="0"><thead><tr><th>分类</th><th>缩写</th><th>作用</th><th>关键字示例</th></tr></thead><tbody><tr><td>数据定义</td><td>DDL</td><td>定义数据库对象（库/表/索引）</td><td>CREATE、DROP、ALTER</td></tr><tr><td>数据操作</td><td>DML</td><td>操作数据（增删改查）</td><td>INSERT、DELETE、UPDATE、SELECT</td></tr><tr><td>数据控制</td><td>DCL</td><td>权限和安全控制</td><td>GRANT、REVOKE</td></tr><tr><td>事务控制</td><td>TCL</td><td>事务管理</td><td>COMMIT、ROLLBACK、SAVEPOINT</td></tr></tbody></table><h2 id="数据库分类" tabindex="-1">数据库分类 <a class="header-anchor" href="#数据库分类" aria-label="Permalink to “数据库分类”">​</a></h2><p>除了关系型数据库，还有其他类型的数据库：</p><h3 id="键值数据库-kv-store" tabindex="-1">键值数据库（KV Store） <a class="header-anchor" href="#键值数据库-kv-store" aria-label="Permalink to “键值数据库（KV Store）”">​</a></h3><ul><li>Redis、Memcached</li><li>适合缓存、Session 存储、排行榜</li><li>优点：读写极快</li><li>缺点：只能按 key 查，不支持复杂查询</li></ul><h3 id="文档数据库" tabindex="-1">文档数据库 <a class="header-anchor" href="#文档数据库" aria-label="Permalink to “文档数据库”">​</a></h3><ul><li>MongoDB</li><li>数据以 JSON 文档形式存储，schema 灵活</li><li>适合内容管理、日志系统</li></ul><h3 id="列式数据库" tabindex="-1">列式数据库 <a class="header-anchor" href="#列式数据库" aria-label="Permalink to “列式数据库”">​</a></h3><ul><li>HBase、Cassandra</li><li>按列存储，适合海量数据分析</li><li>适合 OLAP 场景</li></ul><h3 id="图数据库" tabindex="-1">图数据库 <a class="header-anchor" href="#图数据库" aria-label="Permalink to “图数据库”">​</a></h3><ul><li>Neo4j</li><li>擅长处理关系网络（社交网络、知识图谱）</li></ul><p>大多数业务系统，关系型数据库（MySQL/PostgreSQL）仍然是首选。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to “下一步”">​</a></h2><p>理解了数据库的基本概念，下一章我们来看看<strong>关系型数据库和 ER 模型</strong>——搞清楚数据表之间是怎么关联的，为什么这样设计。</p>`,46)])])}const k=s(n,[["render",l]]);export{b as __pageData,k as default};
